下面是一段使用mmap系统调用访问物理内存的C语言代码示例：

```
#include <fcntl.h>
#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>

#define MEM_DEVICE "/dev/mem"
#define BLOCK_SIZE 4096
#define TARGET_ADDRESS 0x200000    // 设置需要访问的物理地址

int main(int argc, char *argv[]) {
    int mem_fd;
    void *mapped_mem;
    volatile unsigned int *target_address;

    // 打开/dev/mem设备文件，并获取文件描述符
    mem_fd = open(MEM_DEVICE, O_RDWR | O_SYNC);
    if(mem_fd < 0) {
        printf("Failed to open %s\n", MEM_DEVICE);
        return -1;
    }

    // 映射物理地址到用户空间
    mapped_mem = mmap(NULL, BLOCK_SIZE, PROT_READ | PROT_WRITE, MAP_SHARED, mem_fd, TARGET_ADDRESS & ~(BLOCK_SIZE - 1));
    target_address = (volatile unsigned int *)(mapped_mem + (TARGET_ADDRESS & (BLOCK_SIZE - 1)));

    // 读取物理地址上的值
    printf("Value at 0x%x: 0x%x\n", TARGET_ADDRESS, *target_address);

    // 写入物理地址
    *target_address = 0x1234;

    // 关闭文件描述符，释放映射
    close(mem_fd);
    munmap(mapped_mem, BLOCK_SIZE);

    return 0;
}
```

上述代码中，首先通过open函数打开/dev/mem设备文件，并获取文件描述符。然后使用mmap函数将物理地址映射到用户空间，获取到访问物理地址的指针。最后可以通过读取或者写入该指针处的值来访问指定的物理内存地址。最后关闭文件描述符，释放映射。需要注意的是，代码中使用了volatile关键字，以确保编译器不会对访问物理地址的操作进行优化。
